class Solution:
    def maxProfitAssignment(self, difficulty, profit, worker):
        jobs = sorted(zip(difficulty, profit))
        worker = sorted(worker)
        total = 0
        i = 0
        best = 0
        for w in worker:
            while i < len(jobs) and jobs[i][0] <= w:
                if jobs[i][1] > best:
                    best = jobs[i][1]
                i += 1
            total += best
        return total

